import RobotoMedium from '../font/roboto/Roboto-Medium.ttf';

const isWindows = function () {
  return /windows|win32/i.test(navigator.userAgent);
};

export async function loadRoboto() {
  if (typeof window === 'undefined' || typeof FontFace === 'undefined') {
    return;
  }

  const mediumFontFace = new FontFace('Roboto', `url(${RobotoMedium})`, {
    weight: '500',
  });

  const windowsFontFaces = [mediumFontFace];
  const macFontFaces = [mediumFontFace];

  await Promise.all(
    (isWindows() ? windowsFontFaces : macFontFaces).map(async font =>
      font.load().then(() => {
        document.fonts.add(font);
      }),
    ),
  );
}
